            totalCost += C[i];
        }
        return totalCost;
    } else {
        // M is even. K_max is achieved by two maximally dense configurations:
        // I1: {1, 3, 5, ..., M-1} (Starting at 1)
        // I2: {2, 4, 6, ..., M} (Starting at 2)

        let cost1 = 0;
        // Sum for I1 (Odd indices)
        for (let i = 1; i <= M - 1; i += 2) {
            cost1 += C[i];
        }

        let cost2 = 0;
        // Sum for I2 (Even indices)
        for (let i = 2; i <= M; i += 2) {
            cost2 += C[i];
        }

        return Math.min(cost1, cost2);
    }
}
